// Destructor
//-------------------------------------------------------------------------
MRFGrooveSweepCmd::~MRFGrooveSweepCmd()
{
	if (_GrooveSweepDlg != NULL)
		_GrooveSweepDlg->RequestDelayedDestruction();
		_GrooveSweepDlg = NULL;

	if (_GrooveSweepInsertDlg != NULL)
		_GrooveSweepInsertDlg->RequestDelayedDestruction();
		_GrooveSweepInsertDlg = NULL;

	if (_GrooveSweepRemoveDlg != NULL)
		_GrooveSweepRemoveDlg->RequestDelayedDestruction();
		_GrooveSweepRemoveDlg = NULL;

	if (_pathElementAgentCurve != NULL)
		_pathElementAgentCurve->RequestDelayedDestruction(); _pathElementAgentCurve = NULL;

	if (_pathElementCurve != NULL)
		_pathElementCurve = NULL;

	if (_dialogAgentCurve != NULL)
		_dialogAgentCurve->RequestDelayedDestruction(); _dialogAgentCurve = NULL;
	
	if (_pathElementAgentTopSurface != NULL)
		_pathElementAgentTopSurface->RequestDelayedDestruction(); _pathElementAgentTopSurface = NULL;

	if (_pathElementAgentBaseSurface != NULL)
		_pathElementAgentBaseSurface->RequestDelayedDestruction(); _pathElementAgentBaseSurface = NULL;

	if (_pathElementTopSurface != NULL)
		_pathElementTopSurface = NULL;

	if (_dialogAgentTopSurface != NULL)
		_dialogAgentTopSurface->RequestDelayedDestruction(); _dialogAgentTopSurface = NULL;

	if (_pathElementBaseSurface != NULL)
		_pathElementBaseSurface = NULL; 

	if (_dialogAgentBaseSurface != NULL)
		_dialogAgentBaseSurface->RequestDelayedDestruction(); _dialogAgentBaseSurface = NULL;

	if (_pEditor != NULL)
		_pEditor = NULL;

	if (_pSelected3DCurve != NULL)
		_pSelected3DCurve->Release(); _pSelected3DCurve = NULL;

	if (_pBaseSurface != NULL)
		_pBaseSurface->Release(); _pBaseSurface = NULL;

	if (_pTopSurface != NULL)
		_pTopSurface->Release(); _pTopSurface = NULL;

	if (_MRFIGrooveSweep != NULL)
		_MRFIGrooveSweep->Release(); _MRFIGrooveSweep = NULL;

	if (NULL != _pGeoFactory)
		_pGeoFactory->Release(); _pGeoFactory = NULL;

	if (_pDlgAgentCtxtMenu3DCurve != NULL)
		_pDlgAgentCtxtMenu3DCurve->RequestDelayedDestruction(); _pDlgAgentCtxtMenu3DCurve = NULL;

	if (_pDlgAgentCtxtMenuTopSurface != NULL)
		_pDlgAgentCtxtMenuTopSurface->RequestDelayedDestruction(); _pDlgAgentCtxtMenuTopSurface = NULL;

	if (_pDlgAgentCtxtMenuBaseSurface != NULL)
		_pDlgAgentCtxtMenuBaseSurface->RequestDelayedDestruction(); _pDlgAgentCtxtMenuBaseSurface = NULL;	
	
	if (_pEdgeDlgAgent != NULL)
		_pEdgeDlgAgent->RequestDelayedDestruction(); _pEdgeDlgAgent = NULL;	
	
	if (_pEdgePathElementAgent != NULL)
		_pEdgePathElementAgent->RequestDelayedDestruction(); _pEdgePathElementAgent = NULL;

	_edgeList.RemoveAll();
	_EdgeListAsCell.RemoveAll();
	_listAngleRef.RemoveAll();
	_listEdgIndxCtrlPtsParam.RemoveAll();

	/*CATViewer *  pViewer = CATViewer::GetCurrentViewer();
	if (pViewer)
	{
		pViewer->RemoveReps(_pRep);
		pViewer->RemoveReps(_p3DBagRep);
		pViewer->RemoveReps(_p3DBagArrowRep);
	}*/
	if (NULL != _p3DBagRep)
	_p3DBagRep = NULL;

	if (NULL != _pRep)
		_pRep = NULL;

	if (NULL != _p3DBagArrowRep)
		_p3DBagArrowRep = NULL;

	if (NULL != _pEdgeRep)
		_pEdgeRep = NULL;

	if (NULL != _HSO && !_HSO->IsNull())
	{
		//_HSO->Empty();
		_HSO = NULL;
	}

	if (NULL != _pISO && !_pISO->IsNull())
	{
		_pISO->RemoveElement(_pCenterBoxModel);
		_pISO->RemoveElement(_pCPBoxModel);
		_pISO->RemoveElement(_pPointOnEdgeModel);
		_pISO->RemoveElement(_pEdgeModel);
		_pISO->Empty();
		_pISO = NULL;
	}
	if (NULL != _pApplication)
		_pApplication = NULL;


	if (NULL != _pCenterBoxModel)
	{
		_pCenterBoxModel->UnreferenceRep();
		_pCenterBoxModel->Release(); _pCenterBoxModel = NULL;
	}
	if (NULL != _pCPBoxModel)
	{
		_pCPBoxModel->UnreferenceRep();
		_pCPBoxModel->Release(); _pCPBoxModel = NULL;
	}
	if (NULL != _pPointOnEdgeModel)
	{
		_pPointOnEdgeModel->UnreferenceRep();
		_pPointOnEdgeModel->Release(); _pPointOnEdgeModel = NULL;
	}
	if (NULL != _pEdgeModel)
	{
		_pEdgeModel->UnreferenceRep();
		_pEdgeModel->Release(); _pEdgeModel = NULL;
	}
}


