	/*AddAnalyseNotificationCB(edgeIdxCtrlPtsMultiList, edgeIdxCtrlPtsMultiList->GetListCellModifyNotification(), (CATCommandMethod)&MRFGrooveSweepCmd::OnEdgeIndexCtrlPointsMultiListEdited, NULL);*/
