//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::MRFGrooveSweepDlg_ApplyBtnPushed
//Function: This function gets called when user clicks the "Apply" push button from the main window of groove sweep dlg
//Creation Mode = 1; Edit Mode  = 0; If create mode, Creation of groove is done. if edit mode, updation of groove is done.
//-------------------------------------------------------------------------
void MRFGrooveSweepCmd::MRFGrooveSweepDlg_ApplyBtnPushed(
	CATCommand           * ipControl,
	CATNotification      * ipNotification,
	CATCommandClientData   iUsefulData)
{
	if (NULL_var == _pSelected3DCurve)
	{
		ShowErrorMessage("No3DCurve");
		return;
	}
	else if (NULL_var == _pTopSurface)
	{
		ShowErrorMessage("NoTopSurface");
		return;
	}
	else if (NULL_var != _pSelected3DCurve && NULL_var != _pTopSurface)
	{
		if (NULL_var == _spBodyOn3DCurve)
			MRFGenericUtils::GetBodyOfObject(_pSelected3DCurve, _spBodyOn3DCurve);

		if (NULL_var == _spBodyOnTopSurface)
			MRFGenericUtils::GetBodyOfObject(_pTopSurface, _spBodyOnTopSurface);

		if (NULL_var != _spBodyOnTopSurface && NULL_var != _spBodyOn3DCurve)
		{
			CATBoolean result = MRFGenericUtils::DoesBodyContainsBody(_spBodyOnTopSurface, _spBodyOn3DCurve);
			if (!result)
			{
				ShowErrorMessage("Wrong3DCurve");
				return;
			}
		}
	}

	if (!_OnApplyClicked)
	{
		if (ValidateTableValues())
			_OnApplyClicked = CATTrue;

		// Begin of User Code
		if (_OnApplyClicked)
		{
			if (1 == _mode)
			{
				this->CreateGrooveSweep();
				if (_bTrimBase)
					TrimBaseSurface();
				_mode = 0;
			}				
			else if (0 == _mode)
			{
				this->UpdateGrooveSweep();
				if (!!_MRFIGrooveSweep)
				{
					CATBaseUnknown_var spBaseTrimObject;
					_MRFIGrooveSweep->GetTrimBaseObject(spBaseTrimObject);
					if (NULL_var != spBaseTrimObject)
					{
						UpdateTrimBaseOnEdit(spBaseTrimObject);
					}
					else if (_bTrimBase)
						TrimBaseSurface();
				}
			}
				

			if (NULL != _MRFIGrooveSweep && !_bOnPreview)
			{
				CATIMmiMechanicalFeature_var spFeatureToDefine;
				if (_bTrimBase)
				{
					_MRFIGrooveSweep->GetTrimBaseObject(spFeatureToDefine);
				}
				else
					spFeatureToDefine = _MRFIGrooveSweep;
				if (NULL_var != spFeatureToDefine)
				{
					CATIVisProperties * pVisProperties = NULL;
					spFeatureToDefine->QueryInterface(IID_CATIVisProperties, (void**)& pVisProperties);
					if (NULL != pVisProperties)
					{
						CATVisPropertiesValues VisPropValues;
						VisPropValues.SetShow(CATShowAttr);

						pVisProperties->SetPropertiesAtt(VisPropValues, CATVPShow, CATVPGlobalType);

						CATIModelEvents_var MyFeatureModelEventsTool = spFeatureToDefine;
						CATModify NotifModify(spFeatureToDefine);
						MyFeatureModelEventsTool->Dispatch(NotifModify);

						CATIRedrawEvent_var spRedrawEvent = spFeatureToDefine;
						if (NULL_var != spRedrawEvent) spRedrawEvent->Redraw();

						pVisProperties->Release(); pVisProperties = NULL;

					}
					CATPrtUpdateCom *pUpdateCommand = new CATPrtUpdateCom(spFeatureToDefine, 0, 0);
				}
			}
		}	
	}

}

