//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::MRFGrooveSweepInsertDlg_InsertBtnPushed
//Function: This function gets called when user clicks the "Inser" push button from the Inser Dlg window of groove sweep dlg
//Action: Control Point inserted in the multi list
//------------------------------------------------------------------------
void MRFGrooveSweepCmd::MRFGrooveSweepInsertDlg_InsertBtnPushed(
	CATCommand           * ipControl,
	CATNotification      * ipNotification,
	CATCommandClientData   iUsefulData)
{
	std::cout << "     InsertButtonPushed     " << std::endl;
	
	double ratioValue = 0.0;


	CATBody * pBodyOfEdge = NULL;
	CATBody_var testBody = NULL_var;
	CATBaseUnknown_var iSelectedEdge = _edgeList[_edgeIndex];
	MRFGenericUtils::GetBodyOfObject(iSelectedEdge, testBody);
	
		CATTopData* TopData = NULL;
		CATICGMDynMassProperties3D *pDynMasOpe = CATCGMDynCreateMassProperties3D(TopData, testBody);

		double ComputedLength;
		if (NULL != pDynMasOpe)
		{
			 ComputedLength = pDynMasOpe->GetLength();
			 pDynMasOpe->Release(); pDynMasOpe = NULL;
		}

		if (_IsSpinnerEnabled)
		{
			CATDlgSpinner* spinnerCurveRatio = NULL;
			spinnerCurveRatio = _GrooveSweepInsertDlg->GetSpinnerCurveRatio();

			ratioValue = spinnerCurveRatio->GetValue();
			//ratioValue *= 1000; //to convert into mm
		}
		else
		{
			CATDlgSpinner* spinnerCurveDistance = NULL;
			spinnerCurveDistance = _GrooveSweepInsertDlg->GetSpinnerCurveDistance();
			
			ratioValue = spinnerCurveDistance->GetValue();
			ratioValue *= 1000; //to convert into mm

			ratioValue = (ratioValue / ComputedLength);
		}

		if (ratioValue == 0 || ratioValue == 1 || ratioValue > 1)
		{
			this->ShowErrorMessage("InsertBttn");
			return;

		}

	EdgeInfo* edgeInfo = (EdgeInfo*)_listEdgeInfo[_edgeIndex];
	EdgeInfo::ControlPointsInfo* infoControlPoints = new EdgeInfo::ControlPointsInfo();

	infoControlPoints->ratio = ratioValue;

	infoControlPoints->Depth1 = 10.0;
	infoControlPoints->Angle1 = 0.0;

	infoControlPoints->Depth2 = 0.0;
	infoControlPoints->Angle2 = 0.0;

	infoControlPoints->Depth3 = 0.0;
	infoControlPoints->Angle3 = 0.0;

	infoControlPoints->Depth4 = 0.0;
	infoControlPoints->Angle4 = 0.0;

	infoControlPoints->Depth5 = 0.0;
	infoControlPoints->Angle5 = 0.0;

	edgeInfo->listOfControlPointsInfo.Append(infoControlPoints);

	this->UpdateEdgeIdxCtrlPtsMultiListUI(_edgeIndex);
	_GrooveSweepInsertDlg->RequestDelayedDestruction();
	_GrooveSweepInsertDlg = NULL;
}

