CATBoolean MRFGrooveSweepCmd::OnTopSurfaceSel(void *)
{
	if (!_pathElementTopSurface)
	{
		_pathElementTopSurface = _pathElementAgentTopSurface->GetValue();

		if (_pathElementTopSurface)
		{
			// Add current selection to HSO if not added yet
			if (NULL != _HSO && 0 == _HSO->IsMember(_pathElementTopSurface))
			{
				_HSO->Empty();
				_HSO->AddElement(_pathElementTopSurface);
			}

			CATBaseUnknown* pSelectedTopSurface = _pathElementTopSurface->CurrentElement(); // No need to release the returned object
			if (pSelectedTopSurface)
			{
				if (NULL != _pTopSurface)
					_pTopSurface = NULL;

				if (NULL_var != _spBodyOnTopSurface)
					_spBodyOnTopSurface = NULL_var;

				_pTopSurface = pSelectedTopSurface;

				//CATIAlias_var pAliasON3DCurve(pSelectedCurve);
				CATIAlias_var pAliasONTopSurface(_pTopSurface);

				CATUnicodeString nameTopSurface;
				if (pAliasONTopSurface != NULL_var)
					nameTopSurface = pAliasONTopSurface->GetAlias();

				CATDlgSelectorList* pSelectorListTopSurface = _GrooveSweepDlg->GetSelectorListTopSurface();
				if (pSelectorListTopSurface)
				{
					pSelectorListTopSurface->ClearLine();
					pSelectorListTopSurface->SetLine(nameTopSurface);
					pSelectorListTopSurface->ClearSelect();

				}
				CATDlgSelectorList* p3DCurveSelector = _GrooveSweepDlg->GetSelectorList3DCurve();
				if (p3DCurveSelector)
				{
					p3DCurveSelector->ClearSelect();
				}

				CATDlgSelectorList* pSelectorListBaseSurface = _GrooveSweepDlg->GetSelectorListBaseSurface();
				if (pSelectorListBaseSurface)
				{
					MRFGrooveSweepDlg::SetFocusOnSelectorList(pSelectorListBaseSurface);
				}
			}
		}
		_pathElementAgentTopSurface->InitializeAcquisition();
	}

	return CATTrue;
}

