//Function: validates the depth value and angle value
//-----------------------------------------------------------------------
CATBoolean MRFGrooveSweepCmd::ValidateTableValues()
{
	CATBoolean bValid = CATTrue;
	if (_listEdgeInfo.Size() > 0)
	{
		for (int i = 1; i <= _listEdgeInfo.Size(); i++)
		{
			EdgeInfo* edgeInfo = (EdgeInfo*)_listEdgeInfo[i];

			CATRawCollPV listOfControlPointsInfo = edgeInfo->listOfControlPointsInfo;
			int nbControlPoints = edgeInfo->listOfControlPointsInfo.Size();
			CATListOfDouble ListDepth1, ListDepth2, ListDepth3, ListDepth4, ListDepth5;
			
			for (int j = 1; j <= nbControlPoints; j++)
			{
				EdgeInfo::ControlPointsInfo* pControlPointInfo = (EdgeInfo::ControlPointsInfo*)edgeInfo->listOfControlPointsInfo[j];
				double ratio = pControlPointInfo->ratio;
				double angle1, angle2, angle3, angle4, angle5;

				double depth1 = pControlPointInfo->Depth1;
				if (depth1 <= 0 )
				{
					bValid = CATFalse;
					ShowErrorMessage("NegativeDepth");
					break;
				}
				ListDepth1.Append(depth1);
				angle1 = pControlPointInfo->Angle1;
				double depth2 = pControlPointInfo->Depth2;
				if (depth2 > 0 || (ratio > 0 && ListDepth2.Size() > 0))
				{
					ListDepth2.Append(depth2);
					angle2 = pControlPointInfo->Angle2;
					double depth3 = pControlPointInfo->Depth3;
					if (depth3 > 0 || (ratio > 0 && ListDepth3.Size() > 0))
					{
						ListDepth3.Append(depth3);
						angle3 = pControlPointInfo->Angle3;
						double depth4 = pControlPointInfo->Depth4;
						if (depth4 > 0 || (ratio > 0 && ListDepth4.Size() > 0))
						{
							ListDepth4.Append(depth4);
							angle4 = pControlPointInfo->Angle4;
							double depth5 = pControlPointInfo->Depth5;
							if (depth5 > 0 || (ratio > 0 && ListDepth5.Size() > 0))
								ListDepth5.Append(depth5);
							angle5 = pControlPointInfo->Angle5;
						}
					}
				}
				/*if (angle1 < 0 || angle2 < 0 || angle3 < 0 || angle4 < 0 || angle5 < 0)
				{
					bValid = CATFalse;
					ShowErrorMessage("NegativeAngle");
					break;
				}*/
			}
			int NbDepth = ListDepth1.Size();

			if ((ListDepth2.Size() > 0 && ListDepth2.Size() != NbDepth) || (ListDepth3.Size() > 0 && ListDepth3.Size() != NbDepth) || (ListDepth4.Size() > 0 && ListDepth4.Size() != NbDepth) || (ListDepth5.Size() > 0 && ListDepth5.Size() != NbDepth))
			{
				bValid = CATFalse;
			}

			if (bValid)
			{
				CATBoolean bUniformDepths = CATFalse;
				if (AreDepthsUniform(ListDepth1))
				{
					if (ListDepth2.Size() > 1 && AreDepthsUniform(ListDepth2))
					{
						if (ListDepth3.Size() > 1 && AreDepthsUniform(ListDepth3))
						{
							if (ListDepth4.Size() > 1 && AreDepthsUniform(ListDepth4))
							{
								if (ListDepth5.Size() > 1 && AreDepthsUniform(ListDepth5))
								{
									bUniformDepths = CATTrue;
								}
								else if (ListDepth5.Size() <= 1)
									bUniformDepths = CATTrue;
							}
							else if (ListDepth4.Size() <= 1)
								bUniformDepths = CATTrue;
						}
						else if (ListDepth3.Size() <= 1)
							bUniformDepths = CATTrue;
					}
					else if (ListDepth2.Size() <= 1)
						bUniformDepths = CATTrue;
				}
				else
				{
					if (ListDepth2.Size() > 1)
						bUniformDepths = CATFalse;
					else
						bUniformDepths = CATTrue;
				}

				if (!bUniformDepths)
				{
					bValid = CATFalse;
					ShowErrorMessage("NonUniformDepths");
					break;
				}
			}
			else
			{
				ShowErrorMessage("NonUniformDepths");
				break;
			}

		}
	}
	return bValid;
}

//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::AreDepthsUniform
//Input: CATListOfDouble iListDepths
//Function: validates the depth value are same at all control points of same edge.
//-----------------------------------------------------------------------
CATBoolean MRFGrooveSweepCmd::AreDepthsUniform(CATListOfDouble iListDepths)
{
	CATBoolean bUniform = CATTrue;
	double DepthAtO = iListDepths[1];
	for (int i = 1; i <= iListDepths.Size(); i++)
	{
		if (iListDepths[i] != DepthAtO)
		{
			bUniform = CATFalse;
			break;
		}
	}
	return bUniform;
}

//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::OnBaseSurfaceSel
//Function: when base surface is selected in graphic window, its path and name are retrieved and sset in base surface selector liost.
//-----------------------------------------------------------------------
CATBoolean MRFGrooveSweepCmd::OnBaseSurfaceSel(void *)
{
	if (!_pathElementBaseSurface)
	{
		_pathElementBaseSurface = _pathElementAgentBaseSurface->GetValue();

		if (_pathElementBaseSurface)
		{
			// Add current selection to HSO if not added yet
			if (NULL != _HSO && 0 == _HSO->IsMember(_pathElementBaseSurface))
			{
				_HSO->Empty();
				_HSO->AddElement(_pathElementBaseSurface);
			}

			CATBaseUnknown* pSelectedBaseSurface = _pathElementBaseSurface->CurrentElement(); // No need to release the returned object
			if (pSelectedBaseSurface)
			{
				if (NULL_var != _pBaseSurface)
					_pBaseSurface = NULL_var;
				_pBaseSurface = pSelectedBaseSurface;

				//CATIAlias_var pAliasON3DCurve(pSelectedCurve);
				CATIAlias_var pAliasBaseSurface(_pBaseSurface);

				CATUnicodeString strBaseSurface;
				if (pAliasBaseSurface != NULL_var)
					strBaseSurface = pAliasBaseSurface->GetAlias();

				CATDlgSelectorList* pSelectorListBaseSurface = _GrooveSweepDlg->GetSelectorListBaseSurface();
				if (pSelectorListBaseSurface)
				{
					pSelectorListBaseSurface->ClearLine();
					pSelectorListBaseSurface->SetLine(strBaseSurface);
					pSelectorListBaseSurface->ClearSelect();

					if (_bExtrapolateTrim)
					{
						CATDlgCheckButton* pTriBaseCheck = _GrooveSweepDlg->GetTrimBaseCheckButton();
						if (NULL != pTriBaseCheck)
						{
							pTriBaseCheck->SetSensitivity(CATDlgEnable);
						}
					}
				}
				CATDlgCombo* pComboBoxOnEdgeList = _GrooveSweepDlg->GetComboBoxEdge();
				if (NULL != pComboBoxOnEdgeList)
				{
					int edge = 0;
					pComboBoxOnEdgeList->SetSelect(edge, 1);
				}
			}
		}
		_pathElementAgentBaseSurface->InitializeAcquisition();
	}

	return CATTrue;
}

