//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::CreateGrooveSweep
//Function: creates the groove sweep feature using factory and list of selected input.
//-----------------------------------------------------------------------
HRESULT MRFGrooveSweepCmd::CreateGrooveSweep()
{
	HRESULT rc = E_FAIL;

	this->SortEdgeInfoClassList();

	UpdateCtrlPtsParamInfo();
	//_AngleRef = GetAngleReferenceSelected();

	//CATIGSMTool* pGSMTool = NULL;
	//MRFGenericUtils::LookingForGeomSet(pGSMTool, _pEditor);

	CATIMmiMechanicalFeature_var spSelectedCurve = _pSelected3DCurve;
	if (NULL_var != spSelectedCurve)
	{
		CATIMmiPrtContainer_var spPrtCont = NULL_var;
		rc = spSelectedCurve->GetPrtContainer(spPrtCont);
		if (SUCCEEDED(rc) && spPrtCont != NULL_var)
		{
			MRFIGSDFactory *piMRFGSDFactory = NULL;
			rc = spPrtCont->QueryInterface(IID_MRFIGSDFactory, (void**)& piMRFGSDFactory);
			if (SUCCEEDED(rc))
			{    
				rc = piMRFGSDFactory->CreateGrooveSweep(_pSelected3DCurve, _pBaseSurface, _pTopSurface, _edgeList, _listAngleRef, _listEdgIndxCtrlPtsParam, _MRFIGrooveSweep);
				piMRFGSDFactory->Release();
				piMRFGSDFactory = NULL;
			}

			if (SUCCEEDED(rc) && NULL != _MRFIGrooveSweep)
			{
				if (_bExtrapolateTrim)
				{
					_MRFIGrooveSweep->SetExtrapolateTrim(1);
					if (_bTrimBase)
						_MRFIGrooveSweep->SetTrimBase(1);
					else
						_MRFIGrooveSweep->SetTrimBase(0);
				}
				else if (!_bExtrapolateTrim)
				{
					_MRFIGrooveSweep->SetExtrapolateTrim(0);
					_MRFIGrooveSweep->SetTrimBase(0);
				}

				if (_bOnPreview)
				{
					CATDlgCombo* pComboBoxOnEdgeList = _GrooveSweepDlg->GetComboBoxEdge();
					int edgeIndex = pComboBoxOnEdgeList->GetSelect();
					edgeIndex += 1;

					_MRFIGrooveSweep->SetPreviewUptoIndex(edgeIndex);
				}
				else
				{
					_MRFIGrooveSweep->SetPreviewUptoIndex(0);
				}

				int iVersion = 2;
				_MRFIGrooveSweep->SetVersion(iVersion);

				_MRFIGrooveSweep->UpdateFeature();
				CATIMmiUseBasicInsertion_var hBasicInsertion = _MRFIGrooveSweep;
				if (SUCCEEDED(rc) && (NULL_var != hBasicInsertion))
				{
					CATIMmiMechanicalFeature_var spMechanicalPart;
					rc = spPrtCont->GetMechanicalPart(spMechanicalPart);
					if (SUCCEEDED(rc) && NULL_var != spMechanicalPart)
					{
						CATIPartRequest * pPartRequest = NULL;
						rc = spMechanicalPart->QueryInterface(IID_CATIPartRequest, (void**)&pPartRequest);
						if (SUCCEEDED(rc) && NULL != pPartRequest)
						{
							/*CATBaseUnknown_var spMainBody;
							pPartRequest->GetMainBody("MfDefault3DView", spMainBody);
							if (NULL_var != spMainBody)
							{
								CATIMmiMechanicalFeature_var spPartBody = spMainBody;
								if (NULL_var != spPartBody)
								{
									*/
							CATIMmiMechanicalFeature_var spPartBody;
							CATIMmiMechanicalFeature_var spGrooveSweep = _MRFIGrooveSweep;
							if (NULL_var != spGrooveSweep)
							{
								CATIMmiUsePrtPart_var spPrt = spMechanicalPart;
								if (NULL_var != spPrt)
								{
									CATIBasicTool_var spBasicTool;
									CATIMmiMechanicalFeature_var spCurrentInworkObject;
									spPrt->GetInWorkObject(spCurrentInworkObject);
									if (NULL_var != spCurrentInworkObject)
									{
										spBasicTool = spCurrentInworkObject;
										if (NULL_var == spBasicTool)
										{
											hBasicInsertion->InsertAfter(spCurrentInworkObject);
											spGrooveSweep->GetMechanicalFather(spPartBody);
										}
									}
									if (NULL_var == spPartBody)
									{
										spPrt->GetInWorkObjectTool(spBasicTool);
										if (NULL_var != spBasicTool)
										{
											spPartBody = spBasicTool;
											hBasicInsertion->InsertInside(spPartBody);
										}
									}
									rc = spPrt->SetInWorkObject(spGrooveSweep);
									CATIModelEvents_var MyFeatureModelEvents = spGrooveSweep;

									if (NULL_var != MyFeatureModelEvents && NULL_var != spPartBody)
									{
										CATModify NotifModify(spGrooveSweep);
										MyFeatureModelEvents->Dispatch(NotifModify);

										/*MyFeatureModelEvents->ConnectTo(spPartBody);
										CATCreate Notif(spGrooveSweep, spPartBody);
										CATIModelEvents_var MyFeatureModelEventsTool = spPartBody;
										MyFeatureModelEventsTool->Receive(NotifModify);
										MyFeatureModelEventsTool->Dispatch(NotifModify);*/

										CATIRedrawEvent_var spRedrawEvent = spPartBody;
										if (NULL_var != spRedrawEvent) spRedrawEvent->Redraw();
									}
								}
								rc = S_OK;
								CATPrtUpdateCom *pUpdateCommand = new CATPrtUpdateCom(spPartBody, 1, 0);
							}

							pPartRequest->Release();
							pPartRequest = NULL;
						}

					}
				}


			}
		}
	}

	return rc;
}


//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::CreateEdgeInfoClass
//Function: creates the class which has info of edges, its control p[oints, angle and depth value.
//-----------------------------------------------------------------------
void MRFGrooveSweepCmd::CreateEdgeInfoClass()
{
	int edgeSize = _edgeList.Size();
	int nEdgeCellSize = _EdgeListAsCell.Size();

	if (0 < nEdgeCellSize && nEdgeCellSize == edgeSize)
	{
		_listEdgeInfo.RemoveAll();

		for (int i = 1; i <= edgeSize; ++i)
		{
			EdgeInfo* edgeInfo = new EdgeInfo();

			CATBaseUnknown_var spOnEdge = _EdgeListAsCell[i];
			if (NULL != spOnEdge)
			{
				CATEdge_var spOnEdgeCell = spOnEdge;
				if (NULL_var != spOnEdgeCell)
				{
					if (_AccuracyModeList.Size() >= i)
						edgeInfo->AccuracyValue = _AccuracyModeList[i];

					CATVertex * startPoint = NULL;
					CATVertex * endPoint = NULL;
					spOnEdgeCell->GetVertices(&startPoint, &endPoint);

					if (NULL != startPoint && NULL != endPoint)
					{
						CATRawCollPV pointListPerEdge;
						pointListPerEdge.Append((CATBaseUnknown*)startPoint);
						pointListPerEdge.Append((CATBaseUnknown*)endPoint);

						_pointList.Append(pointListPerEdge); // It will store point list on each edge in seperate Index

						int pointSize = pointListPerEdge.Size();

						if (pointSize > 0)
						{
							for (int j = 1, k = 0; j <= pointSize; ++j, ++k)
							{
								EdgeInfo::ControlPointsInfo* infoControlPoints = new EdgeInfo::ControlPointsInfo();

								infoControlPoints->ratio = k;

								infoControlPoints->Depth1 = 10.0;
								infoControlPoints->Angle1 = 0.0;

								infoControlPoints->Depth2 = 0.0;

								infoControlPoints->Depth3 = 0.0;
								infoControlPoints->Angle3 = 0.0;

								infoControlPoints->Depth4 = 0.0;
								infoControlPoints->Angle4 = 0.0;
								infoControlPoints->Angle2 = 0.0;

								infoControlPoints->Depth5 = 0.0;
								infoControlPoints->Angle5 = 0.0;

								edgeInfo->listOfControlPointsInfo.Append(infoControlPoints);
							}
							_listEdgeInfo.Append(edgeInfo);
						}
					}
				}
			}
		}
	}	
}

//-------------------------------------------------------------------------
