//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::UpdateCtrlPtsParamInfo
//Function: updates control parameters info
//-----------------------------------------------------------------------
void MRFGrooveSweepCmd::UpdateCtrlPtsParamInfo()
{
	_listEdgIndxCtrlPtsParam.RemoveAll();
	int edgeSize = _listEdgeInfo.Size();
	if (edgeSize > 0)
	{
		int rowCount = 1;
		for (int i = 1; i <= edgeSize; ++i)
		{
			EdgeInfo* edgeInfo = (EdgeInfo*)_listEdgeInfo[i];
			if (NULL != edgeInfo)
			{
				CATUnicodeString idxEdge;
				idxEdge.BuildFromNum(i);
				_listEdgIndxCtrlPtsParam.Append(idxEdge);

				_listEdgIndxCtrlPtsParam.Append("^");
				if (_AccuracyModeList.Size() >= i)
				{
					CATUnicodeString strAccuracyMode;
					strAccuracyMode.BuildFromNum(edgeInfo->AccuracyValue);
					_listEdgIndxCtrlPtsParam.Append(strAccuracyMode);
				}					
				else
					_listEdgIndxCtrlPtsParam.Append("0");

				_listEdgIndxCtrlPtsParam.Append("<");

				CATRawCollPV infoControlPoints = edgeInfo->listOfControlPointsInfo;

				for (int idxCp = 1; idxCp <= infoControlPoints.Size(); idxCp++)
				{
					EdgeInfo::ControlPointsInfo* iControlPointInfo = (EdgeInfo::ControlPointsInfo*) infoControlPoints[idxCp];
					if (!!iControlPointInfo)
					{
						CATUnicodeString idxStrCtrlPoint;
						idxStrCtrlPoint.BuildFromNum(iControlPointInfo->ratio);
						_listEdgIndxCtrlPtsParam.Append(idxStrCtrlPoint);
						_listEdgIndxCtrlPtsParam.Append(":");

						GetCtrlPtsParamInfo(iControlPointInfo);
						if (idxCp != infoControlPoints.Size()) _listEdgIndxCtrlPtsParam.Append("|");

					}
				}
			}
			if (i != edgeSize) _listEdgIndxCtrlPtsParam.Append(">");
		}
	}
	/*CATViewer *  pViewer = CATViewer::GetCurrentViewer();
	if (pViewer && _p3DBagArrowRep)
	{
		_p3DBagArrowRep->Empty();
		pViewer->RemoveReps(_p3DBagArrowRep);
	}*/
	if (NULL != _pCPBoxModel && NULL != _pISO)
	{
		_pCPBoxModel->UnreferenceRep();
		_pISO->RemoveElement(_pCPBoxModel);
	}
}

//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::UpdateCtrlPtsParamInfo
//Function: updates edge info
//-----------------------------------------------------------------------
void MRFGrooveSweepCmd::UpdateEdgeInfoClass(int edgeIndex)
{
	if (_listEdgeInfo.Size() > 0 && edgeIndex <= _listEdgeInfo.Size())
	{
		_OnApplyClicked = CATFalse;
		CATDlgMultiList* edgeIdxCtrlPtsMultiList = NULL;
		edgeIdxCtrlPtsMultiList = _GrooveSweepDlg->GetMultiListControlPoints();

		int rowCount, columnCount;

		rowCount = edgeIdxCtrlPtsMultiList->GetLineCount();
		columnCount = edgeIdxCtrlPtsMultiList->GetColumnCount();

		int row, column;
		//row = edgeIdxCtrlPtsMultiList->GetSelect(&row, 1);
		//edgeIdxCtrlPtsMultiList->GetModifiedCell(row, column);
		edgeIdxCtrlPtsMultiList->GetSelect(&row, 1);

		EdgeInfo* edgeInfo = (EdgeInfo*)_listEdgeInfo[edgeIndex];
		if (row >= 0 && row < edgeInfo->listOfControlPointsInfo.Size())
		{
			bool edgeInfoListCreated = false;
			EdgeInfo::ControlPointsInfo* infoControlPoints = (EdgeInfo::ControlPointsInfo*)edgeInfo->listOfControlPointsInfo[row + 1];
			for (column = 0; column <= 10; column++)
			{
				CATUnicodeString strNewValue;
				edgeIdxCtrlPtsMultiList->GetColumnItem(column, strNewValue, row);

				switch (column)
				{
				case 0:
					strNewValue.ConvertToNum(&(infoControlPoints->ratio), "%le");
					break;
				case 1:
					strNewValue.ConvertToNum(&(infoControlPoints->Depth1), "%le");
					break;
				case 2:
					strNewValue.ConvertToNum(&(infoControlPoints->Angle1), "%le");
					break;
				case 3:
					strNewValue.ConvertToNum(&(infoControlPoints->Depth2), "%le");
					break;
				case 4:
					strNewValue.ConvertToNum(&(infoControlPoints->Angle2), "%le");
					break;
				case 5:
					strNewValue.ConvertToNum(&(infoControlPoints->Depth3), "%le");
					break;
				case 6:
					strNewValue.ConvertToNum(&(infoControlPoints->Angle3), "%le");
					break;
				case 7:
					strNewValue.ConvertToNum(&(infoControlPoints->Depth4), "%le");
					break;
				case 8:
					strNewValue.ConvertToNum(&(infoControlPoints->Angle4), "%le");
					break;
				case 9:
					strNewValue.ConvertToNum(&(infoControlPoints->Depth5), "%le");
					break;
				case 10:
					strNewValue.ConvertToNum(&(infoControlPoints->Angle5), "%le");
					break;
				}
			}
		}
	}
}

//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::OnComboBoxEdgeModified
//Function: when combo box edge are modified its respective control points are updated in multi list UI
//-----------------------------------------------------------------------
void MRFGrooveSweepCmd::OnComboBoxEdgeModified(CATCommand * ipControl, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	CATDlgCombo* pComboBoxOnEdgeList = _GrooveSweepDlg->GetComboBoxEdge();
	_edgeIndex = pComboBoxOnEdgeList->GetSelect(); //sets the active edge index to the global variable "_edgeIndex"
	_edgeIndex += 1;

	if (_edgeList.Size() > 0 && _edgeIndex <= _edgeList.Size())
	{
		CATBaseUnknown_var iSelectedEdge = _edgeList[_edgeIndex];
		if (iSelectedEdge != NULL_var && NULL != _HSO && NULL != _pEditor)
		{
			CATIBuildPath_var piBuildPath = NULL_var;
			HRESULT rc = iSelectedEdge->QueryInterface(IID_CATIBuildPath, (void**)&piBuildPath);
			if (SUCCEEDED(rc) && NULL_var != piBuildPath)
			{
				CATPathElement Context = _pEditor->GetUIActiveObject();
				CATPathElement * pPathElement = NULL;
				rc = piBuildPath->ExtractPathElement(&Context, &pPathElement);

				if (NULL !=  pPathElement)
				{
					_HSO->Empty();
					_HSO->AddElement(pPathElement);

					pPathElement->Release();
					pPathElement = NULL;
				}

				piBuildPath->Release();
				piBuildPath = NULL;
			}
		}
	}

	/*CATViewer *  pViewer = CATViewer::GetCurrentViewer();
	if (pViewer && _p3DBagArrowRep)
	{
		_p3DBagArrowRep->Empty();
		pViewer->RemoveReps(_p3DBagArrowRep);
	}*/
	if (NULL != _pCPBoxModel && NULL != _pISO)
	{
		_pCPBoxModel->UnreferenceRep();
		_pISO->RemoveElement(_pCPBoxModel);
	}

	this->UpdateEdgeIdxCtrlPtsMultiListUI(_edgeIndex);
	this->MRFGrooveSweepDlg_SortBtnPushed(NULL, NULL, NULL);
	_GrooveSweepDlg->HideSpinnerEditor();
}

