//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::UpdateGrooveSweep
//Function: update the groove sweep feature with the updated input values.
//-----------------------------------------------------------------------
HRESULT MRFGrooveSweepCmd::UpdateGrooveSweep()
{
	HRESULT rc = E_FAIL;

	if (NULL != _MRFIGrooveSweep)
	{
		this->SortEdgeInfoClassList();
		UpdateCtrlPtsParamInfo();
		//_AngleRef = GetAngleReferenceSelected();

		if (NULL_var != _pSelected3DCurve)
			rc = _MRFIGrooveSweep->SetInput3DCurve(_pSelected3DCurve);

		//if (NULL_var != _pBaseSurface)
			rc = _MRFIGrooveSweep->SetBaseSurface(_pBaseSurface);

		if (NULL_var != _pTopSurface)
			rc = _MRFIGrooveSweep->SetTopSurface(_pTopSurface);

		if (_edgeList.Size() > 0)
			rc = _MRFIGrooveSweep->SetEdgeList(_edgeList);

		/*if (_AngleRef > -1)
			rc = _MRFIGrooveSweep->SetAngleRef(_AngleRef);*/

		if (_listAngleRef.Size() > 0)
			rc = _MRFIGrooveSweep->SetAngleRefList(_listAngleRef);

		if (_listEdgIndxCtrlPtsParam.Size() > 0)
			rc = _MRFIGrooveSweep->SetEdgeIndexAndControlPointParams(_listEdgIndxCtrlPtsParam);

		if (_bExtrapolateTrim)
		{
			_MRFIGrooveSweep->SetExtrapolateTrim(1);
			if (_bTrimBase)
				_MRFIGrooveSweep->SetTrimBase(1);
			else
				_MRFIGrooveSweep->SetTrimBase(0);
		}
		else if (!_bExtrapolateTrim)
		{
			_MRFIGrooveSweep->SetExtrapolateTrim(0);
			_MRFIGrooveSweep->SetTrimBase(0);
		}
		
		if (_bOnPreview)
		{
			CATDlgCombo* pComboBoxOnEdgeList = _GrooveSweepDlg->GetComboBoxEdge();
			int edgeIndex = pComboBoxOnEdgeList->GetSelect();
			edgeIndex += 1;

			_MRFIGrooveSweep->SetPreviewUptoIndex(edgeIndex);
		}
		else
		{
			_MRFIGrooveSweep->SetPreviewUptoIndex(0);
		}
		_mode = 0;
		_MRFIGrooveSweep->UpdateFeature();

		if (!_bOnPreview)
		{
			CATIMmiMechanicalFeature_var spCurrentFeature = _MRFIGrooveSweep;
			CATIModelEvents_var MyFeatureModelEvents = spCurrentFeature;

			if (NULL_var != MyFeatureModelEvents)
			{
				CATModify NotifModify(spCurrentFeature);
				MyFeatureModelEvents->Dispatch(NotifModify);

				CATIMmiMechanicalFeature_var spGSMTool;
				spCurrentFeature->GetMechanicalFather(spGSMTool);
				/*MyFeatureModelEvents->ConnectTo(spGSMTool);
				CATCreate Notif(spCurrentFeature, spGSMTool);
				

				CATIModelEvents_var MyFeatureModelEventsTool = spGSMTool;
				CATModify NotifModify(spGSMTool);

				MyFeatureModelEventsTool->Receive(NotifModify);
				MyFeatureModelEventsTool->Dispatch(NotifModify);*/

				CATIRedrawEvent_var spRedrawEvent = spGSMTool;
				if (NULL_var != spRedrawEvent) spRedrawEvent->Redraw();

				CATPrtUpdateCom *pUpdateCommand = new CATPrtUpdateCom(spGSMTool, 1, 0);
			}
		}
	}

	return rc;
}

//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::CreateEdgeListInfoForEdit
//Function: update the groove sweep feature with the updated input values.
//-----------------------------------------------------------------------
void MRFGrooveSweepCmd::CreateEdgeListInfoForEdit()
{
	_listEdgeInfo.RemoveAll();
	CATUnicodeString strCtrlPtsParam;
	for (int i = 1; i <= _listEdgIndxCtrlPtsParam.Size(); i++)
	{
		strCtrlPtsParam.Append(_listEdgIndxCtrlPtsParam[i]);
	}
	stringstream strStream(strCtrlPtsParam.ConvertToChar());

	string line = "";
	vector< string > rtvecEdge;
	const char delimEdge = '>';
	
	// Iterate through each line and split the content using delimeter
	while (getline(strStream, line, delimEdge))
	{
		if (!line.empty()) 
		{
			rtvecEdge.push_back(line);
			//cout << line << endl;
		}
	}

	for (auto it = rtvecEdge.begin(); it != rtvecEdge.end(); it++) 
	{
		//cout << " -- " << *it << endl;
		EdgeInfo* edgeInfo = new EdgeInfo();
		stringstream strEntry = (stringstream)*it;
		line = "";
		const char delimCP = '<';
		vector< string > rtvecCP;
		while (getline(strEntry, line, delimCP))
		{
			if (!line.empty()) 
			{
				rtvecCP.push_back(line);
				//cout << line << endl;
			}
		}

		stringstream strEdgeEntry = (stringstream)*rtvecCP.begin();
		line = "";
		const char delimAcc = '^';
		vector< string > AccuracyVector;
		while (getline(strEdgeEntry, line, delimAcc))
		{
			if (!line.empty())
			{
				AccuracyVector.push_back(line);
				//cout << line << endl;
			}
		}

		int AccuracyModeIndex = 0;
		if (AccuracyVector.size() > 1)
		{
			string strAccuracy = (string)*(AccuracyVector.begin() + 1);
			CATUnicodeString strAccuracyMode = strAccuracy.c_str();
			strAccuracyMode.ConvertToNum(&AccuracyModeIndex);			
		}
		edgeInfo->AccuracyValue = AccuracyModeIndex;
		_AccuracyModeList.Append(AccuracyModeIndex);

		for (auto itC = rtvecCP.begin()+1; itC != rtvecCP.end(); itC++)
		{
			stringstream strEntry1 = (stringstream)*itC;
			line = "";
			const char delimCP1 = '|';
			vector< string > rtvecCP1;
			while (getline(strEntry1, line, delimCP1))
			{
				if (!line.empty()) 
				{
					rtvecCP1.push_back(line);
					//cout << line << endl;
				}
			}

			for (auto it1 = rtvecCP1.begin(); it1 != rtvecCP1.end(); it1++)
			{
				stringstream strEntry2 = (stringstream)*it1;
				line = "";
				const char delimCP2 = ':';
				vector< string > rtvecCP2;
				while (getline(strEntry2, line, delimCP2))
				{
					if (!line.empty())
					{
						rtvecCP2.push_back(line);
						//cout << line << endl;
					}
				}

				EdgeInfo::ControlPointsInfo* iControlPointInfo = new EdgeInfo::ControlPointsInfo;
				string strCPtsParam = (string)*rtvecCP2.begin();
				CATUnicodeString strCATCPtsParam = strCPtsParam.c_str();
				double dCPtParam;
				if (1 == strCATCPtsParam.ConvertToNum(&dCPtParam) && 2 == rtvecCP2.size())
				{
					iControlPointInfo->ratio = dCPtParam;

					stringstream strEntry3 = (stringstream)*(rtvecCP2.begin()+1);
					line = "";
					const char delimCP3 = ',';
					vector< string > rtvecCP3;
					while (getline(strEntry3, line, delimCP3))
					{
						if (!line.empty())
						{
							rtvecCP3.push_back(line);
							//cout << line << endl;
						}
					}

					if (10 == rtvecCP3.size())
					{
						double dCPtDepth1Param, dCPtDepth2Param, dCPtDepth3Param, dCPtDepth4Param, dCPtDepth5Param;
						double dCPtAngle1Param, dCPtAngle2Param, dCPtAngle3Param, dCPtAngle4Param, dCPtAngle5Param;

						string strDepth1Param = (string)*(rtvecCP3.begin());
						CATUnicodeString strCPtsDepth1Param = strDepth1Param.c_str();
						strCPtsDepth1Param.ConvertToNum(&dCPtDepth1Param);
						iControlPointInfo->Depth1 = dCPtDepth1Param;

						string strAngle1Param = (string)*(rtvecCP3.begin() + 1);
						CATUnicodeString strCPtsAngle1Param = strAngle1Param.c_str();
						strCPtsAngle1Param.ConvertToNum(&dCPtAngle1Param);
						iControlPointInfo->Angle1 = dCPtAngle1Param;

						string strDepth2Param = (string)*(rtvecCP3.begin() + 2);
						CATUnicodeString strCPtsDepth2Param = strDepth2Param.c_str();
						strCPtsDepth2Param.ConvertToNum(&dCPtDepth2Param);
						iControlPointInfo->Depth2 = dCPtDepth2Param;

						string strAngle2Param = (string)*(rtvecCP3.begin() + 3);
						CATUnicodeString strCPtsAngle2Param = strAngle2Param.c_str();
						strCPtsAngle2Param.ConvertToNum(&dCPtAngle2Param);
						iControlPointInfo->Angle2 = dCPtAngle2Param;

						string strDepth3Param = (string)*(rtvecCP3.begin() + 4);
						CATUnicodeString strCPtsDepth3Param = strDepth3Param.c_str();
						strCPtsDepth3Param.ConvertToNum(&dCPtDepth3Param);
						iControlPointInfo->Depth3 = dCPtDepth3Param;

						string strAngle3Param = (string)*(rtvecCP3.begin() + 5);
						CATUnicodeString strCPtsAngle3Param = strAngle3Param.c_str();
						strCPtsAngle3Param.ConvertToNum(&dCPtAngle3Param);
						iControlPointInfo->Angle3 = dCPtAngle3Param;

						string strDepth4Param = (string)*(rtvecCP3.begin() + 6);
						CATUnicodeString strCPtsDepth4Param = strDepth4Param.c_str();
						strCPtsDepth4Param.ConvertToNum(&dCPtDepth4Param);
						iControlPointInfo->Depth4 = dCPtDepth4Param;

						string strAngle4Param = (string)*(rtvecCP3.begin() + 7);
						CATUnicodeString strCPtsAngle4Param = strAngle4Param.c_str();
						strCPtsAngle4Param.ConvertToNum(&dCPtAngle4Param);
						iControlPointInfo->Angle4 = dCPtAngle4Param;

						string strDepth5Param = (string)*(rtvecCP3.begin() + 8);
						CATUnicodeString strCPtsDepth5Param = strDepth5Param.c_str();
						strCPtsDepth5Param.ConvertToNum(&dCPtDepth5Param);
						iControlPointInfo->Depth5 = dCPtDepth5Param;

						string strAngle5Param = (string)*(rtvecCP3.begin() + 9);
						CATUnicodeString strCPtsAngle5Param = strAngle5Param.c_str();
						strCPtsAngle5Param.ConvertToNum(&dCPtAngle5Param);
						iControlPointInfo->Angle5 = dCPtAngle5Param;

					}
				}
				edgeInfo->listOfControlPointsInfo.Append(iControlPointInfo);

			}

		}
		_listEdgeInfo.Append(edgeInfo);
	}	
	for (int edgeIndex = 1; edgeIndex <= _listEdgeInfo.Size(); edgeIndex++)
		UpdateEdgeIdxCtrlPtsMultiListUI(edgeIndex);
}

//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::ShowErrorMessage
//Function: show error msg
//-----------------------------------------------------------------------
void MRFGrooveSweepCmd::ShowErrorMessage(CATUnicodeString dlgName)
{
	CATApplicationFrame * pAppFrame = CATApplicationFrame::GetFrame();
	if (NULL == pAppFrame)
		return;

	CATDlgWindow * pMainWindow = pAppFrame->GetMainWindow();
	if (NULL == pMainWindow)
		return;

	CATDlgNotify * pErrPanel = new CATDlgNotify(pMainWindow, "Error", CATDlgNfyOK | CATDlgNfyError | CATDlgWndModal);
	if (NULL == pErrPanel)
		return;

	// Set the text
	CATUnicodeString usWndTitle = "Please check input values";

	if (dlgName == "InsertBttn")
	{
		CATUnicodeString usMessage = "Please Enter Valid Value";
		pErrPanel->DisplayBlocked(usMessage, usWndTitle);
	}
	else if (dlgName == "RemoveBttn")
	{
		CATUnicodeString usMessage = "Default Points Cannot be removed";
		usMessage.Append("\nSelect Other Points");
		pErrPanel->DisplayBlocked(usMessage, usWndTitle);
	}
	else if (dlgName == "NonUniformDepths")
	{
		CATUnicodeString usMessage = "Depths defined are not uniform";
		usMessage.Append("\nPlease input correct Depths");
		pErrPanel->DisplayBlocked(usMessage, usWndTitle);
	}
	else if (dlgName == "NegativeAngle")
	{
		CATUnicodeString usMessage = "Angle defined is a negative draft angle";
		usMessage.Append("\nPlease input correct Angles");
		pErrPanel->DisplayBlocked(usMessage, usWndTitle);
	}
	else if (dlgName == "Wrong3DCurve")
	{
		CATUnicodeString usMessage = "Selected 3DCurve does no lie on selected top surface";
		usMessage.Append("\nPlease re select the 3D Curve or tyre surface");
		pErrPanel->DisplayBlocked(usMessage, usWndTitle);
	}
	else if (dlgName == "NegativeDepth")
	{
		CATUnicodeString usMessage = "Depth1 defined should be greater than 0";
		usMessage.Append("\nPlease input correct Depths");
		pErrPanel->DisplayBlocked(usMessage, usWndTitle);
	}
	else if (dlgName == "No3DCurve")
	{
		CATUnicodeString usMessage = "No 3D Curve Selected";
		usMessage.Append("\nPlease Select Input 3D Curve or Cancel the Command");
		pErrPanel->DisplayBlocked(usMessage, usWndTitle);
	}
	else if (dlgName == "NoTopSurface")
	{
		CATUnicodeString usMessage = "No Top Surface Selected";
		usMessage.Append("\nPlease Select Top Surface or Cancel the Command");
		pErrPanel->DisplayBlocked(usMessage, usWndTitle);
	}	
	else if (dlgName == "ChangeInput3DCurve")
	{
		CATUnicodeString usMessage = "3DCurve has been changed OR Edges in 3DCurve has been changed";
		usMessage.Append("\nPlease re-select correct 3DCurve");
		pErrPanel->DisplayBlocked(usMessage, usWndTitle);
	}
	pErrPanel->RequestDelayedDestruction(); pErrPanel = NULL;
}

//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::SortEdgeInfoClassList
//Function: sort edge info class list when sort push button is clicked on UI
//-----------------------------------------------------------------------
void MRFGrooveSweepCmd::SortEdgeInfoClassList()
{
	if (_listEdgeInfo.Size() > 0)
	{
		for (int i = 1; i <= _listEdgeInfo.Size(); ++i)
		{
			EdgeInfo* edgeInfo = (EdgeInfo*)_listEdgeInfo[i];
			
			CATRawCollPV listOfControlPointsInfoBackUp = edgeInfo->listOfControlPointsInfo;

			for (int j = 2; j <= edgeInfo->listOfControlPointsInfo.Size(); ++j)
			{
				EdgeInfo::ControlPointsInfo* iControlPointInfoMin = (EdgeInfo::ControlPointsInfo*)edgeInfo->listOfControlPointsInfo[j];
				double ratioMin = iControlPointInfoMin->ratio;

				int indexToRemove = j;
				for (int k = j+1; k <= edgeInfo->listOfControlPointsInfo.Size(); ++k)
				{
					EdgeInfo::ControlPointsInfo* iControlPointInfoMin = (EdgeInfo::ControlPointsInfo*)edgeInfo->listOfControlPointsInfo[k];
					double ratioCurrent = iControlPointInfoMin->ratio;

					if (ratioMin == ratioCurrent)
						continue;
					else if (ratioMin > ratioCurrent )
					{
						ratioMin = ratioCurrent;
						indexToRemove = k;
					}
					if (k == edgeInfo->listOfControlPointsInfo.Size())
					{
						EdgeInfo::ControlPointsInfo* iControlPointInfoTest = (EdgeInfo::ControlPointsInfo*)listOfControlPointsInfoBackUp[indexToRemove];
						listOfControlPointsInfoBackUp.RemovePosition(indexToRemove);
						listOfControlPointsInfoBackUp.InsertAt(j, iControlPointInfoTest);

						edgeInfo->listOfControlPointsInfo = listOfControlPointsInfoBackUp;
					}
				}
			}
		}
	}
}

//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::Create3DCustomRepForPoints
//Function: to visualise control poits in graphic window, creates the repsective points.
//-----------------------------------------------------------------------
CAT3DCustomRep* MRFGrooveSweepCmd::Create3DCustomRepForPoints(float pointArray[], int nbPoints)
{
	CAT3DCustomRep * iopPointsRep = CAT3DCustomRep::CreateRep();
	CAT3DMarkerGP * pPointGP = new CAT3DMarkerGP(pointArray, nbPoints, CROSS);

	CATGraphicAttributeSet AttributePoint;
	AttributePoint.SetColor(WHITE);

	iopPointsRep->AddGP(pPointGP, AttributePoint);
	iopPointsRep->SetThickness(50);

	CAT3DBoundingSphere be(pointArray, 0.f, 1.f);
	iopPointsRep->SetBoundingElement(be);

	return iopPointsRep;
}

//-------------------------------------------------------------------------
// MRFGrooveSweepCmd::Create3DArrow
//Function: create the 3D arrow to visualise the surface normal in graphhic window
//-----------------------------------------------------------------------
CAT3DCustomRep* MRFGrooveSweepCmd::Create3DArrow(double iPoint[3], CATUnicodeString istrRatio, const CATMathDirection & iSweepDirection, const CATMathDirection & iSurfaceNormal, const CATMathDirection & iNormalDirection, const int iDepth, const int iColor)
{
	CAT3DCustomRep * iop3DArrowRep = CAT3DCustomRep::CreateRep();

	CATMathPoint MathPoint(iPoint);
	CATMathPointf MathPointF = MathPoint;
	CATMathDirectionf SweepDirectionF(iSweepDirection);
	CATMathDirectionf SurfaceNormalDirectionF(iSurfaceNormal);
	CATMathDirectionf NormalDirectionF(iNormalDirection);

	/*CATMathLine MathLine;
	MathLine.Set(MathPoint, iSweepDirection);
	MathLine.SetLineScale(iDepth - 1);

	CATMathPoint MidPoint;
	MathLine.EvalPoint(1, MidPoint);
	CATMathPointf MidPointf = MidPoint;*/

	CATMathLine NormalLine;
	NormalLine.Set(MathPoint, iSurfaceNormal);
	NormalLine.SetLineScale(iDepth);
	
	CATMathPoint NormalPoint;
	NormalLine.EvalPoint(1, NormalPoint);
	CATMathPointf NormalPointF = NormalPoint;

	CAT3DArrowGP * pArrowGP = new CAT3DArrowGP(MathPointF, SweepDirectionF, iDepth, 1);
	CAT3DArrowGP * pArrowGPSurfaceNormal = new CAT3DArrowGP(MathPointF, SurfaceNormalDirectionF, iDepth);
	CAT3DArrowGP * pArrowGPNormal = new CAT3DArrowGP(MathPointF, NormalDirectionF, iDepth);

	CATGraphicAttributeSet AttributePoint;

	if (1 == iColor)
	{
		AttributePoint.SetColor(CYAN);
	}
	else if(2 == iColor)
	{
		AttributePoint.SetColor(RED);
	}
	else if (3 == iColor)
	{
		AttributePoint.SetColor(GREEN);
	}
	else if (4 == iColor)
	{
		AttributePoint.SetColor(MAGENTA);
	}
	else if (5 == iColor)
	{
		AttributePoint.SetColor(BLACK);
	}

	AttributePoint.SetThickness(5);
	AttributePoint.SetType(1);

	CATGraphicAttributeSet AttributePointNormal;
	AttributePointNormal.SetColor(YELLOW);
	AttributePointNormal.SetThickness(2);
	AttributePointNormal.SetLineType(3);

	CATGraphicAttributeSet AttributePointSurfaceNormal;
	AttributePointSurfaceNormal.SetColor(WHITE);
	AttributePointSurfaceNormal.SetThickness(2);
	AttributePointSurfaceNormal.SetLineType(3);

	//double catAngle = iSweepDirection.GetAngleTo(iSurfaceNormal);

	CATUnicodeString strAnnot = istrRatio;
	CAT3DAnnotationTextGP * pAnnotCPTGP = new CAT3DAnnotationTextGP(MathPointF, strAnnot, BOTTOM_CENTER);
	iop3DArrowRep->AddGP(pAnnotCPTGP, AttributePoint);

	CATUnicodeString strSurface = "Surface Normal";
	CAT3DAnnotationTextGP * pAnnotNormalGP = new CAT3DAnnotationTextGP(NormalPointF, strSurface, TOP_CENTER);
	iop3DArrowRep->AddGP(pAnnotNormalGP, AttributePointSurfaceNormal);

	//CATUnicodeString strAngle;
	//strAngle.BuildFromNum(catAngle);

	//pArrowGP->AssociateText((char*)strAngle.ConvertToChar());
	
	//pArrowGPSurfaceNormal->AssociateText((char*)strSurface.ConvertToChar());
	iop3DArrowRep->AddGP(pArrowGP, AttributePoint);
	iop3DArrowRep->AddGP(pArrowGPSurfaceNormal, AttributePointSurfaceNormal);
	if (_AngleRef > 0)
	{
		CATMathLine AngleLine;
		AngleLine.Set(MathPoint, iNormalDirection);
		AngleLine.SetLineScale(iDepth);

		CATMathPoint AnglePoint;
		AngleLine.EvalPoint(1, AnglePoint);
		CATMathPointf AnglePointF = AnglePoint;

		CATUnicodeString strDraftDirection = "Draft Direction";
		CAT3DAnnotationTextGP * pAnnotNormalGP = new CAT3DAnnotationTextGP(AnglePointF, strDraftDirection, BOTTOM_CENTER);
		//pArrowGPNormal->AssociateText((char*)strDraftDirection.ConvertToChar());
		iop3DArrowRep->AddGP(pAnnotNormalGP, AttributePointNormal);
		iop3DArrowRep->AddGP(pArrowGPNormal, AttributePointNormal);

	}
		

	iop3DArrowRep->SetThickness(5);


	CAT3DBoundingSphere be(MathPointF, 0.f, 1.f);
	iop3DArrowRep->SetBoundingElement(be);
	return iop3DArrowRep;

}

