	if (pSelectorListBaseSurface)
		pSelectorListBaseSurface->ClearSelect();

	CATDlgMultiList* edgeIdxCtrlPtsMultiList = NULL;
	edgeIdxCtrlPtsMultiList = _GrooveSweepDlg->GetMultiListControlPoints();
