	edgeIdxCtrlPtsMultiList->GetSelect(&row, 1);
	if (row >= 0 && row < edgeIdxCtrlPtsMultiList->GetLineCount())
	{
		edgeIdxCtrlPtsMultiList->SetSelect(&row, 1, 0);
		_GrooveSweepDlg->DisplaySpinnerEditor();
		CATUnicodeString Depth1, Depth2, Depth3, Depth4, Depth5;
		CATUnicodeString Angle1, Angle2, Angle3, Angle4, Angle5;
		edgeIdxCtrlPtsMultiList->GetColumnItem(1, Depth1, row);
		edgeIdxCtrlPtsMultiList->GetColumnItem(2, Angle1, row);
		edgeIdxCtrlPtsMultiList->GetColumnItem(3, Depth2, row);
		edgeIdxCtrlPtsMultiList->GetColumnItem(4, Angle2, row);
		edgeIdxCtrlPtsMultiList->GetColumnItem(5, Depth3, row);
		edgeIdxCtrlPtsMultiList->GetColumnItem(6, Angle3, row);
		edgeIdxCtrlPtsMultiList->GetColumnItem(7, Depth4, row);
		edgeIdxCtrlPtsMultiList->GetColumnItem(8, Angle4, row);
		edgeIdxCtrlPtsMultiList->GetColumnItem(9, Depth5, row);
		edgeIdxCtrlPtsMultiList->GetColumnItem(10, Angle5, row);

		CATDlgCombo* pComboBoxOnEdgeList = _GrooveSweepDlg->GetComboBoxEdge();
		int edgeIndex = pComboBoxOnEdgeList->GetSelect();
		edgeIndex += 1;

		CATUnicodeString oString;
		edgeIdxCtrlPtsMultiList->GetColumnItem(0, oString, row);

		CATListOfDouble DepthList, AngleList;
		double ratio;
		oString.ConvertToNum(&ratio);

		double depth1 = -1;
		Depth1.ConvertToNum(&depth1);
		if (depth1 > 0 )
		{
			double angle1;
			Angle1.ConvertToNum(&angle1);

			DepthList.Append(depth1);
			AngleList.Append(angle1);
		}

		double depth2 = -1;
		Depth2.ConvertToNum(&depth2);
		if (depth2 > 0 )
		{
			double angle2;
			Angle2.ConvertToNum(&angle2);

			DepthList.Append(depth2);
			AngleList.Append(angle2);
		}

		double depth3 = -1;
		Depth3.ConvertToNum(&depth3);
		if (depth3 > 0 )
		{
			double angle3;
			Angle3.ConvertToNum(&angle3);

			DepthList.Append(depth3);
			AngleList.Append(angle3);
		}

		double depth4 = -1;
		Depth4.ConvertToNum(&depth4);
		if (depth4 > 0)
		{
			double angle4;
			Angle4.ConvertToNum(&angle4);

			DepthList.Append(depth4);
			AngleList.Append(angle4);
		}

		double depth5 = -1;
		Depth5.ConvertToNum(&depth5);
		if (depth5 > 0)
		{
			double angle5;
			Angle5.ConvertToNum(&angle5);

			DepthList.Append(depth5);
			AngleList.Append(angle5);
		}
		_GrooveSweepDlg->UpdateSpinnerEditor(DepthList, AngleList);
		DisplayDirection(edgeIndex, ratio, DepthList, AngleList);
	}
	else
	{
		if (NULL != _pCPBoxModel && NULL != _pISO)
		{
			_pCPBoxModel->UnreferenceRep();
			_pISO->RemoveElement(_pCPBoxModel);
		}
		_GrooveSweepDlg->HideSpinnerEditor();
	}		
